const raw = $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}
let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse JSON: ' + e.message + '. Raw response: ' + raw);
}

const hypotheses = parsed.hypotheses || [];
if (!Array.isArray(hypotheses) || hypotheses.length === 0) {
  throw new Error('No hypotheses array found in parsed JSON. Raw response: ' + raw);
}
for (const h of hypotheses) {
  if (!h.query) {
    throw new Error('One of the hypotheses is missing a query. Raw response: ' + raw);
  }
}
return hypotheses.map(h => ({
  json: {
    hypothesis: h.hypothesis,
    query: h.query
  }
}));

const results = $input.all();
const originalInput = $('Format Schema for LLM').first().json;

let resultsText = '';
results.forEach((item, index) => {
  const splitList = $('Split Queries').all();
  const pairedIdx = item.pairedItem && item.pairedItem.item !== undefined ? item.pairedItem.item : index;
  const h = splitList[pairedIdx] ? splitList[pairedIdx].json : {};
  const query = h.query || 'Unknown query';
  const hypothesis = h.hypothesis || 'Unknown hypothesis';
  let queryResult = '';
  try {
    queryResult = JSON.stringify(item.json);
  } catch (e) {
    queryResult = 'Error stringifying result: ' + e.message;
  }
  resultsText += `Hypothesis ${index + 1}: ${hypothesis}\n`;
  resultsText += `SQL Query Run: ${query}\n`;
  resultsText += `Result Data: ${queryResult}\n\n`;
});

return [{
  json: {
    directives: originalInput.directives,
    kowalski_persona: originalInput.kowalski_persona,
    results_summary: resultsText
  }
}];
